.darma-loader-uiverse-blue-cube-swarm { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-blue-cube-swarm__v3-cube-loader {
position: relative;
width: 160px;
height: 160px;
perspective: 1200px;
display: flex;
justify-content: center;
align-items: center;
transform-style: preserve-3d;
background: transparent;
}

.darma-loader-uiverse-blue-cube-swarm__v3-cube {
position: absolute;
width: 28px;
height: 28px;
background: linear-gradient(135deg, var(--loader-color, #007cf0), var(--loader-secondary-color, #00dfd8));
border-radius: 6px;
transform-style: preserve-3d;
animation: darma-loader-uiverse-blue-cube-swarm-cube-float-3d 3.5s ease-in-out infinite;
animation-delay: calc(var(--i) * 0.2s);
opacity: 0.85;
box-shadow: 0 8px 20px rgba(0, 0, 0, 0.2);
}

@keyframes darma-loader-uiverse-blue-cube-swarm-cube-float-3d {
0% {
transform: translate3d(
calc((var(--i) - 5) * 14px),
calc((var(--i) - 5) * 9px),
0
)
rotateX(0deg) rotateY(0deg) rotateZ(0deg) scale(1);
}

50% {
transform: translate3d(
calc((var(--i) - 5) * 14px),
calc((var(--i) - 5) * 9px),
50px
)
rotateX(180deg) rotateY(180deg) rotateZ(90deg) scale(1.25);
}

100% {
transform: translate3d(
calc((var(--i) - 5) * 14px),
calc((var(--i) - 5) * 9px),
0
)
rotateX(360deg) rotateY(360deg) rotateZ(180deg) scale(1);
}
}

